def parse_packet(data: bytes) -> dict:
    if len(data) < 2:
        raise ValueError("Packet too short for version/command headers")
    length = data[2] if len(data) > 2 else 0
    if len(data) < 2 + length + 1:
        raise ValueError("Packet truncated: insufficient payload or checksum bytes")
    return {
        'version': int.from_bytes(data[0:1], byteorder='big'),
        'command': int.from_bytes(data[1:2], byteorder='big'),
        'length': int.from_bytes(data[2:3], byteorder='big'),
        'payload': data[3:3+length],
        'checksum': int.from_bytes(data[3+length:4+length], byteorder='big')
    }
